// submit.js - Part 4: sends pipeline to backend and shows result alert
import { useState } from 'react';
import { useStore } from './store';
import { shallow } from 'zustand/shallow';

const selector = (state) => ({
  nodes: state.nodes,
  edges: state.edges,
});

export const SubmitButton = () => {
  const { nodes, edges } = useStore(selector, shallow);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://127.0.0.1:8000/pipelines/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodes, edges }),
      });

      if (!response.ok) throw new Error(`Server error: ${response.status}`);

      const data = await response.json();
      const { num_nodes, num_edges, is_dag } = data;

      alert(
        `Pipeline Analysis\n` +
        `─────────────────\n` +
        `Nodes:  ${num_nodes}\n` +
        `Edges:  ${num_edges}\n` +
        `Valid DAG:  ${is_dag ? '✓ Yes' : '✗ No (contains a cycle)'}`
      );
    } catch (err) {
      alert(`Failed to submit pipeline:\n${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '14px',
        background: '#0f1623',
        borderTop: '1px solid rgba(255,255,255,0.07)',
      }}
    >
      <button
        onClick={handleSubmit}
        disabled={loading}
        style={{
          padding: '10px 40px',
          background: loading ? 'rgba(108,99,255,0.4)' : 'linear-gradient(135deg, #6C63FF, #8b5cf6)',
          border: 'none',
          borderRadius: '8px',
          color: '#fff',
          fontSize: '13px',
          fontWeight: '600',
          letterSpacing: '0.05em',
          cursor: loading ? 'not-allowed' : 'pointer',
          fontFamily: "'DM Sans', 'Segoe UI', sans-serif",
          boxShadow: loading ? 'none' : '0 4px 16px rgba(108,99,255,0.35)',
          transition: 'all 0.2s',
        }}
        onMouseEnter={(e) => { if (!loading) e.target.style.transform = 'translateY(-1px)'; e.target.style.boxShadow = '0 6px 20px rgba(108,99,255,0.5)'; }}
        onMouseLeave={(e) => { e.target.style.transform = 'translateY(0)'; e.target.style.boxShadow = '0 4px 16px rgba(108,99,255,0.35)'; }}
      >
        {loading ? 'Analyzing...' : 'Submit Pipeline'}
      </button>
    </div>
  );
};
